mapper.select:
SELECT

FROM sys_file_ a

WHERE a.id = #{id}

SELECT

FROM sys_file_ a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${sqlMap.dsf}


		AND a.owner_code LIKE #{ownerCodeLike}


		AND a.group_id_ = #{groupId}



		AND a.name_ LIKE #{nameLike}


		AND a.type_ = #{type}


		AND a.upload_time_ BETWEEN #{beginUploadTime} AND #{endUploadTime}


		AND a.upload_user_id_ = #{uploadUser.id}


		AND a.sec_flag_ = #{secFlag}


		AND a.to_pdf_ = #{toPdf}




		ORDER BY ${page.orderBy}


		ORDER BY a.sort, a.update_date DESC

SELECT

,a.content_ AS "content"
FROM sys_file_ a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${sqlMap.dsf}


		AND a.owner_code LIKE #{ownerCodeLike}


		AND a.group_id_ = #{groupId}



		AND a.name_ LIKE #{nameLike}


		AND a.type_ = #{type}


		AND a.upload_time_ BETWEEN #{beginUploadTime} AND #{endUploadTime}


		AND a.upload_user_id_ = #{uploadUser.id}


		AND a.sec_flag_ = #{secFlag}


		AND a.to_pdf_ = #{toPdf}




		ORDER BY ${page.orderBy}


		ORDER BY a.sort, a.update_date DESC

SELECT

FROM sys_file_ a

WHERE a.del_flag = '0'
AND (
	a.path_ IN

		#{path}

	OR a.thumb_path_ IN

		#{path}

	OR a.url IN

		#{path}

	OR a.thumb_url IN

		#{path}

)
ORDER BY CASE WHEN a.url IS NOT NULL AND a.url != '' THEN 0 ELSE 1 END, a.update_date DESC

SELECT

FROM sys_file_ a


	a.del_flag = #{DEL_FLAG_NORMAL}



		ORDER BY ${page.orderBy}


		ORDER BY a.update_date DESC

mapper.update:
UPDATE sys_file_ SET
	secret_level = #{secretLevel}
WHERE id = #{id}

UPDATE sys_file_ SET
	del_flag = #{DEL_FLAG_DELETE}
WHERE id = #{id}
